package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.Flushable;
import java.io.IOException;
import java.lang.reflect.Field;

import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.CSVPrinter;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class CSVPrinterFlushTest {

    private CSVFormat format;

    @BeforeEach
    void setUp() {
        format = mock(CSVFormat.class);
    }

    @Test
    void flush_whenOutIsFlushable_flushCalled() throws IOException, NoSuchFieldException, IllegalAccessException {
        Flushable flushableOut = mock(Flushable.class);

        // Create a dummy Appendable that also implements Flushable
        Appendable flushableAppendable = new Appendable() {
            @Override
            public Appendable append(CharSequence csq) {
                return this;
            }

            @Override
            public Appendable append(CharSequence csq, int start, int end) {
                return this;
            }

            @Override
            public Appendable append(char c) {
                return this;
            }
        };

        // Use reflection to create a proxy that implements both Appendable and Flushable
        Object proxy = java.lang.reflect.Proxy.newProxyInstance(
                Appendable.class.getClassLoader(),
                new Class<?>[]{Appendable.class, Flushable.class},
                (proxyObj, method, args) -> {
                    if ("flush".equals(method.getName())) {
                        flushableOut.flush();
                        return null;
                    }
                    // For Appendable methods, do nothing and return this proxy
                    if ("append".equals(method.getName())) {
                        return proxyObj;
                    }
                    return null;
                });

        CSVPrinter printer = new CSVPrinter((Appendable) proxy, format);

        printer.flush();

        verify(flushableOut, times(1)).flush();
    }

    @Test
    void flush_whenOutIsNotFlushable_noException() throws IOException {
        Appendable nonFlushableOut = mock(Appendable.class);
        CSVPrinter printer = new CSVPrinter(nonFlushableOut, format);

        // Should not throw any exception
        assertDoesNotThrow(printer::flush);
    }
}
